type goTypeInfo struct {
	Expr            string
	BaseSpannerType string
	IsArray         bool
	Imports         []ImportSpec
}

var typeQualifierPattern = regexp.MustCompile(`\b([A-Za-z_][A-Za-z0-9_]*)\.`)

